package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrim() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat trimmed = original.withTrim(true);

        assertNotNull(trimmed, "withTrim() should not return null");
        assertTrue(trimmed.getTrim(), "The trim flag should be true after withTrim(true)");
        // Ensure original is not modified (immutability)
        assertFalse(original.getTrim(), "Original CSVFormat should remain untrimmed");
    }
}
